// menu.js - كود مع خلفية مخصصة
import { useState, useEffect } from "react";

export default function Menu() {
  const [mousePosition, setMousePosition] = useState({ x: 0, y: 0 });
  const [textIndex, setTextIndex] = useState(0);
  
  // ⬇️⬇️⬇️ ضع رابط الصورة الذي تريده هنا ⬇️⬇️⬇️
  const backgroundImageUrl = "https://static.vecteezy.com/system/resources/thumbnails/052/726/726/small/italian-food-frame-traditional-national-cuisine-ingredients-pasta-olive-tomatoes-cheese-and-spices-cartoon-restaurant-menu-background-vector.jpg";
  
  const texts = ["مرحباً", "أهلاً", "تفضلوا", "استمتعوا"];

  const cards = [
    { id: 1, name: "شيشة", icon: "💨", color: "#ff6b6b", size: 220, top: "8%", left: "2%", rotate: -6, image: "https://cdn-icons-png.flaticon.com/512/1998/1998626.png" },
    { id: 2, name: "أكل", icon: "🍔", color: "#4ecdc4", size: 200, bottom: "5%", left: "3%", rotate: 4, image: "https://cdn-icons-png.flaticon.com/512/1046/1046784.png" },
    { id: 3, name: "مشروبات", icon: "🥤", color: "#45b7d1", size: 210, top: "12%", right: "2%", rotate: -4, image: "https://cdn-icons-png.flaticon.com/512/1046/1046855.png" },
    { id: 4, name: "ديسار", icon: "🍰", color: "#f9ca24", size: 195, bottom: "8%", right: "3%", rotate: 5, image: "https://cdn-icons-png.flaticon.com/512/1046/1046790.png" }
  ];

  useEffect(() => {
    const interval = setInterval(() => {
      setTextIndex((prev) => (prev + 1) % texts.length);
    }, 2500);
    return () => clearInterval(interval);
  }, []);

  useEffect(() => {
    const handleMouseMove = (e) => {
      setMousePosition({
        x: (e.clientX / window.innerWidth - 0.5) * 40,
        y: (e.clientY / window.innerHeight - 0.5) * 40
      });
    };
    window.addEventListener("mousemove", handleMouseMove);
    return () => window.removeEventListener("mousemove", handleMouseMove);
  }, []);

  const handleCardClick = (cardName) => {
    alert(`✨ لقد اخترت: ${cardName} ✨`);
  };

  return (
    <div style={{
      minHeight: "100vh",
      backgroundImage: `url(${backgroundImageUrl})`,
      backgroundSize: "cover",
      backgroundPosition: "center",
      backgroundRepeat: "no-repeat",
      backgroundAttachment: "fixed",
      position: "relative",
      overflow: "hidden",
      fontFamily: "sans-serif"
    }}>
      
      {/* طبقة شفافة فوق الخلفية لتغميقها قليلاً وجعل النصوص واضحة */}
      <div style={{
        position: "absolute",
        top: 0,
        left: 0,
        right: 0,
        bottom: 0,
        background: "rgba(0,0,0,0.55)",
        pointerEvents: "none",
        zIndex: 1
      }}></div>

      {/* الكاردات - zIndex أعلى من الخلفية */}
      {cards.map((card) => (
        <div
          key={card.id}
          onClick={() => handleCardClick(card.name)}
          style={{
            position: "fixed",
            top: card.top,
            left: card.left,
            right: card.right,
            bottom: card.bottom,
            transform: `
              translate(
                ${mousePosition.x * (card.id % 2 === 0 ? 0.6 : -0.5)}px, 
                ${mousePosition.y * (card.id % 2 === 0 ? -0.5 : 0.6)}px
              ) 
              rotate(${card.rotate}deg)
            `,
            transition: "transform 0.2s ease-out",
            zIndex: 15,
            cursor: "pointer"
          }}
        >
          <div style={{
            background: `linear-gradient(135deg, ${card.color}, ${card.color}cc)`,
            width: `${card.size}px`,
            padding: "35px 20px",
            borderRadius: "45px",
            textAlign: "center",
            boxShadow: "0 30px 60px rgba(0,0,0,0.5)",
            backdropFilter: "blur(8px)",
            border: "2px solid rgba(255,255,255,0.3)",
            transition: "all 0.3s cubic-bezier(0.175, 0.885, 0.32, 1.275)"
          }}
          onMouseEnter={(e) => {
            e.currentTarget.style.transform = `scale(1.1) rotate(${card.rotate + 8}deg)`;
            e.currentTarget.style.boxShadow = "0 45px 80px rgba(0,0,0,0.6)";
            e.currentTarget.style.border = "2px solid rgba(34,197,94,0.9)";
          }}
          onMouseLeave={(e) => {
            e.currentTarget.style.transform = "scale(1) rotate(0deg)";
            e.currentTarget.style.boxShadow = "0 30px 60px rgba(0,0,0,0.5)";
            e.currentTarget.style.border = "2px solid rgba(255,255,255,0.3)";
          }}
          >
            <img 
              src={card.image} 
              alt={card.name} 
              style={{ 
                width: "100px", 
                height: "100px", 
                marginBottom: "15px", 
                filter: "drop-shadow(2px 4px 12px black)" 
              }} 
            />
            <h3 style={{ 
              color: "white", 
              margin: "12px 0 8px", 
              fontSize: "2rem", 
              fontWeight: "bold" 
            }}>{card.name}</h3>
            <span style={{ fontSize: "3rem" }}>{card.icon}</span>
          </div>
        </div>
      ))}

      {/* كلمة MONO في المنتصف */}
      <div style={{
        position: "fixed",
        top: "50%",
        left: "50%",
        transform: `translate(-50%, -50%) translate(${mousePosition.x * 0.15}px, ${mousePosition.y * 0.15}px)`,
        textAlign: "center",
        zIndex: 25,
        transition: "transform 0.15s ease-out",
        pointerEvents: "none"
      }}>
        <h1 style={{
          fontSize: "8rem",
          fontWeight: "900",
          color: "#22c55e",
          margin: 0,
          letterSpacing: "8px",
          textShadow: "0 0 30px rgba(34,197,94,0.8), 0 0 60px rgba(34,197,94,0.5)",
          whiteSpace: "nowrap"
        }}>
          {texts[textIndex]}
        </h1>
        <div style={{
          width: "150px",
          height: "4px",
          background: "linear-gradient(90deg, #22c55e, #4ade80, #22c55e)",
          margin: "30px auto 0",
          borderRadius: "10px"
        }}></div>
      </div>

      <div style={{
        position: "fixed",
        bottom: "25px",
        left: "0",
        right: "0",
        textAlign: "center",
        color: "rgba(255,255,255,0.6)",
        fontSize: "14px",
        zIndex: 30,
        pointerEvents: "none",
        letterSpacing: "1px",
        backgroundColor: "rgba(0,0,0,0.4)",
        padding: "8px",
        width: "fit-content",
        margin: "0 auto",
        borderRadius: "20px",
        left: "50%",
        transform: "translateX(-50%)",
        bottom: "15px"
      }}>
        ✨ اضغط على أي كارد لاختيار المنتج ✨
      </div>
    </div>
  );
}
